    public string WsPath { get; set; } = string.Empty;
    public string WsHost { get; set; } = string.Empty;
    public string GrpcServiceName { get; set; } = string.Empty;
    public string GrpcMode { get; set; } = "gun";
    public string H2Path { get; set; } = string.Empty;
    public string H2Host { get; set; } = string.Empty;
    public string TcpHeaderType { get; set; } = "none";
    public string TcpHost { get; set; } = string.Empty;
