namespace NapsternetVClient.Utilities;

public static class DpapiHelper
{
    private static readonly byte[] Entropy = Encoding.UTF8.GetBytes("NapsternetVClient.v1");

    public static string Protect(string plainText)
    {
        byte[] data = Encoding.UTF8.GetBytes(plainText);
        byte[] protectedData = ProtectedData.Protect(data, Entropy, DataProtectionScope.CurrentUser);
        return Convert.ToBase64String(protectedData);
    }

    public static string Unprotect(string protectedBase64)
    {
        byte[] protectedData = Convert.FromBase64String(protectedBase64);
        byte[] data = ProtectedData.Unprotect(protectedData, Entropy, DataProtectionScope.CurrentUser);
        return Encoding.UTF8.GetString(data);
    }
}

using System.Text.RegularExpressions;

namespace NapsternetVClient.Utilities;

public static partial class LogRedactor
{
    [GeneratedRegex(@"(?i)(password|passwd|pass|uuid|id|token|key)\s*[=:]\s*[^\s,}""]+")]
    private static partial Regex SecretPattern();

    [GeneratedRegex(@"(?i)[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}")]
    private static partial Regex UuidPattern();

    public static string Redact(string line)
    {
        if (string.IsNullOrEmpty(line))
            return line;

        string redacted = SecretPattern().Replace(line, m =>
        {
            int sep = m.Value.IndexOfAny(['=', ':']);
            return sep >= 0 ? m.Value[..(sep + 1)] + "***" : m.Value;
        });

        return UuidPattern().Replace(redacted, "***-uuid-redacted***");
    }
}

