namespace NapsternetVClient.Parsers;

public static class FormatSniffer
{
    public static ConfigFormat Detect(string content, string? fileExtension = null)
    {
        string trimmed = content.Trim();
        string ext = fileExtension?.ToLowerInvariant() ?? string.Empty;

        if (ext == ".npvt" || trimmed.Contains("NPVT1", StringComparison.Ordinal))
            return ConfigFormat.Npvt;

        if (trimmed.StartsWith("vmess://", StringComparison.OrdinalIgnoreCase) ||
            trimmed.StartsWith("vless://", StringComparison.OrdinalIgnoreCase) ||
            trimmed.StartsWith("trojan://", StringComparison.OrdinalIgnoreCase) ||
            trimmed.StartsWith("ss://", StringComparison.OrdinalIgnoreCase))
            return ConfigFormat.ShareUri;

        if (ext is ".npv" or ".npv2" or ".npv4")
            return ConfigFormat.Npv4;

        if (trimmed.TrimStart().StartsWith('{'))
            return ConfigFormat.PlainJson;

        if (Base64Helper.TryDecodeBase64(trimmed, out string? decoded) &&
            decoded!.TrimStart().StartsWith('{') &&
            decoded.Contains("\"version\"", StringComparison.OrdinalIgnoreCase))
            return ConfigFormat.Npv4;

        return ConfigFormat.Unknown;
    }
}

