using System.Diagnostics;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Parsers;

public sealed class NpvtDecoder
{
    private readonly ILogger<NpvtDecoder> _logger;

    public NpvtDecoder(ILogger<NpvtDecoder> logger)
    {
        _logger = logger;
    }

    public async Task<string> DecodeFileAsync(string filePath, string? password = null, CancellationToken ct = default)
    {
        if (!File.Exists(Constants.NpvtDecoderExePath))
            throw new FileNotFoundException(
                "npvt-decoder.exe not found. The app will download Pantegnos on first .npvt import, " +
                "or place the binary manually in %AppData%/NapsternetVClient/bin/npvt-decoder.exe",
                Constants.NpvtDecoderExePath);

        string tempInputDir = Path.Combine(Path.GetTempPath(), "npvt-in-" + Guid.NewGuid().ToString("N"));
        string tempOutputDir = Path.Combine(Path.GetTempPath(), "npvt-out-" + Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(tempInputDir);
        Directory.CreateDirectory(tempOutputDir);

        string tempInputFile = Path.Combine(tempInputDir, Path.GetFileName(filePath));
        File.Copy(filePath, tempInputFile, overwrite: true);

        try
        {
            var psi = new ProcessStartInfo
            {
                FileName = Constants.NpvtDecoderExePath,
                Arguments = $"-input \"{tempInputDir}\" -output \"{tempOutputDir}\"",
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = true,
                WorkingDirectory = Constants.BinDir
            };

            if (!string.IsNullOrWhiteSpace(password))
                psi.Environment["NPVT_PASSWORD"] = password;

            using var process = Process.Start(psi)
                ?? throw new InvalidOperationException("Failed to start npvt-decoder.exe");

            string stdout = await process.StandardOutput.ReadToEndAsync(ct);
            string stderr = await process.StandardError.ReadToEndAsync(ct);
            await process.WaitForExitAsync(ct);

            if (process.ExitCode != 0)
            {
                _logger.LogWarning("npvt-decoder exit {Code}. stderr: {Err}", process.ExitCode, stderr);
                throw new InvalidOperationException(
                    $"Failed to decrypt .npvt file (exit {process.ExitCode}). " +
                    (stderr.Contains("password", StringComparison.OrdinalIgnoreCase)
                        ? "This file may require a password."
                        : stderr));
            }

            var jsonFiles = Directory.GetFiles(tempOutputDir, "*.json", SearchOption.AllDirectories);
            if (jsonFiles.Length == 0)
            {
                var txtFiles = Directory.GetFiles(tempOutputDir, "*.*", SearchOption.AllDirectories)
                    .Where(f => !f.EndsWith(".exe", StringComparison.OrdinalIgnoreCase)).ToArray();
                if (txtFiles.Length == 0)
                    throw new FormatException("Decoder produced no output for .npvt file.");

                return await File.ReadAllTextAsync(txtFiles[0], ct);
            }

            return await File.ReadAllTextAsync(jsonFiles[0], ct);
        }
        finally
        {
            try { Directory.Delete(tempInputDir, true); } catch { }
            try { Directory.Delete(tempOutputDir, true); } catch { }
        }
    }

    public async Task<string> DecodeContentAsync(string content, string? password = null, CancellationToken ct = default)
    {
        string tempFile = Path.Combine(Path.GetTempPath(), $"npvt-{Guid.NewGuid():N}.npvt");
        await File.WriteAllTextAsync(tempFile, content, ct);
        try
        {
            return await DecodeFileAsync(tempFile, password, ct);
        }
        finally
        {
            try { File.Delete(tempFile); } catch { }
        }
    }
}

using NapsternetVClient.Models;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Parsers;

public static class NpvtProfileMapper
{
    public static ServerProfile MapFromWrapper(NpvWrapper wrapper, string sourceName)
    {
        if (wrapper.Config is null)
            throw new FormatException("NPVT decrypted payload has no config section.");

        var profile = MapConfig(wrapper.Config, wrapper.Type, sourceName);
        profile.DnsServer = wrapper.Dns?.Server;
        profile.MuxEnabled = wrapper.Mux?.Enabled ?? false;
        profile.MuxConcurrency = wrapper.Mux?.Concurrency ?? 8;
        return profile;
    }

    public static ServerProfile MapConfig(NpvConfig config, string type, string sourceName)
    {
        var protocol = ParseProtocol(type);
        if (protocol == ProxyProtocol.Ssh)
            throw new NotSupportedException("SSH configs are not supported in this client.");

        return new ServerProfile
        {
            Protocol = protocol,
            Name = config.Remark ?? config.Ps ?? sourceName,
            Address = config.Address ?? string.Empty,
            Port = config.Port,
            UserId = config.Id ?? string.Empty,
            AlterId = config.AlterId,
            Security = config.Security ?? config.Method ?? config.Encryption ?? "auto",
            Password = config.Password ?? string.Empty,
            Flow = config.Flow ?? string.Empty,
            Network = ParseTransport(config.Network ?? "tcp"),
            TlsSecurity = config.Tls ?? string.Empty,
            Sni = config.Sni ?? string.Empty,
            Alpn = config.Alpn ?? string.Empty,
            Fingerprint = config.Fingerprint ?? string.Empty,
            AllowInsecure = config.AllowInsecure,
            WsPath = config.WsPath ?? config.Path ?? string.Empty,
            WsHost = config.WsHost ?? config.Host ?? string.Empty,
            GrpcServiceName = config.ServiceName ?? string.Empty,
            GrpcMode = config.Mode ?? "gun",
            TcpHeaderType = config.HeaderType ?? "none",
            RealityPublicKey = config.PublicKey ?? string.Empty,
            RealityShortId = config.ShortId ?? string.Empty,
            RealitySpiderX = config.SpiderX ?? string.Empty
        };
    }

    public static ProxyProtocol ParseProtocol(string type) => type.ToLowerInvariant() switch
    {
        "vmess" => ProxyProtocol.Vmess,
        "vless" => ProxyProtocol.Vless,
        "trojan" => ProxyProtocol.Trojan,
        "shadowsocks" or "ss" => ProxyProtocol.Shadowsocks,
        "socks" => ProxyProtocol.Socks,
        "ssh" => ProxyProtocol.Ssh,
        _ => throw new NotSupportedException($"Unsupported protocol type: {type}")
    };

    public static TransportType ParseTransport(string network) => network.ToLowerInvariant() switch
    {
        "ws" or "websocket" => TransportType.Ws,
        "grpc" or "gun" => TransportType.Grpc,
        "h2" or "http" => TransportType.H2,
        "quic" => TransportType.Quic,
        "kcp" or "mkcp" => TransportType.Kcp,
        _ => TransportType.Tcp
    };
}

