using System.Globalization;
using System.Windows;
using System.Windows.Data;

namespace NapsternetVClient.Converters;

public sealed class BoolToVisibilityConverter : IValueConverter
{
    public bool Invert { get; set; }

    public object Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        bool flag = value is true;
        if (Invert) flag = !flag;
        return flag ? Visibility.Visible : Visibility.Collapsed;
    }

    public object ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture) =>
        throw new NotSupportedException();
}

public sealed class NullToVisibilityConverter : IValueConverter
{
    public bool Invert { get; set; }

    public object Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        bool hasValue = value is not null;
        if (value is string s) hasValue = !string.IsNullOrWhiteSpace(s);
        if (Invert) hasValue = !hasValue;
        return hasValue ? Visibility.Visible : Visibility.Collapsed;
    }

    public object ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture) =>
        throw new NotSupportedException();
}

public sealed class EnumToBoolConverter : IValueConverter
{
    public object Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is null || parameter is null) return false;
        return value.ToString() == parameter.ToString();
    }

    public object ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is true && parameter is not null)
            return Enum.Parse(targetType, parameter.ToString()!);
        return Binding.DoNothing;
    }
}

using System.Collections.ObjectModel;
using System.Windows;
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using Microsoft.Extensions.Logging;
using Microsoft.Win32;
using NapsternetVClient.Core;
using NapsternetVClient.Models;
using NapsternetVClient.Parsers;
using NapsternetVClient.Services;
using NapsternetVClient.Utilities;
using NapsternetVClient.Views;

namespace NapsternetVClient.ViewModels;

public partial class MainViewModel : ObservableObject, IDisposable
{
    private const int MaxLogLines = 500;

    private readonly ProfileService _profileService;
    private readonly ConnectionService _connectionService;
    private readonly BinaryManager _binaryManager;
    private readonly ParserFactory _parserFactory;
    private readonly ILogger<MainViewModel> _logger;

    public LocalizationService L => LocalizationService.Instance;

    [ObservableProperty]
    private ServerProfile? _selectedProfile;

    [ObservableProperty]
    private ConnectionMode _selectedMode = ConnectionMode.SystemProxy;

    [ObservableProperty]
    private ConnectionState _connectionState = ConnectionState.Disconnected;

    [ObservableProperty]
    private bool _isBusy;

    [ObservableProperty]
    private string _statusMessage = "Ready";

    [ObservableProperty]
    private bool _isLogExpanded;

    [ObservableProperty]
    private string? _toastMessage;

    [ObservableProperty]
    private string? _errorMessage;

    [ObservableProperty]
    private string _busyMessage = string.Empty;

    [ObservableProperty]
    private ProfileDisplayInfo? _selectedProfileDetails;

    public ObservableCollection<ServerProfile> Profiles { get; } = [];
    public ObservableCollection<string> LogLines { get; } = [];

    public bool IsEmpty => Profiles.Count == 0;

    public MainViewModel(
        ProfileService profileService,
        ConnectionService connectionService,
        BinaryManager binaryManager,
        ParserFactory parserFactory,
        ILogger<MainViewModel> logger)
    {
        _profileService = profileService;
        _connectionService = connectionService;
        _binaryManager = binaryManager;
        _parserFactory = parserFactory;
        _logger = logger;

        _connectionService.StateChanged += OnConnectionStateChanged;
        _connectionService.LogReceived += OnLogReceived;
        L.PropertyChanged += (_, _) => RefreshLocalizedStatus();
    }

    public Task InitializeAsync()
    {
        if (!EnsureDisclaimerAccepted())
        {
            Application.Current.Shutdown();
            return Task.CompletedTask;
        }

        Profiles.Clear();
        foreach (var profile in _profileService.Profiles)
            Profiles.Add(profile);

        ConnectionState = _connectionService.State;
        StatusMessage = L["Ready"];
        AppendLog("Application started.");
        OnPropertyChanged(nameof(IsEmpty));
        return Task.CompletedTask;
    }

    [RelayCommand]
    private void ToggleLanguage()
    {
        L.ToggleLanguage();
        OnPropertyChanged(nameof(L));
    }

    [RelayCommand]
    private void ToggleLog() => IsLogExpanded = !IsLogExpanded;

    [RelayCommand]
    private void SelectProxyMode() => SelectedMode = ConnectionMode.SystemProxy;

    [RelayCommand]
    private void SelectTunMode() => SelectedMode = ConnectionMode.Tun;

    [RelayCommand]
    private async Task ImportFileAsync()
    {
        var dialog = new OpenFileDialog
        {
            Title = L["ImportFile"],
            Filter = "Napsternet configs|*.npvt;*.npv4;*.npv;*.npv2|All files|*.*",
            Multiselect = false
        };

        if (dialog.ShowDialog() != true)
            return;

        await ImportFilePathAsync(dialog.FileName);
    }

    [RelayCommand]
    private async Task ImportUriAsync()
    {
        string? uri = null;
        await UiDispatcher.RunAsync(() =>
        {
            uri = InputDialog.Prompt(
                Application.Current.MainWindow,
                L["ImportUriTitle"],
                L["ImportUriPrompt"]);
        });

        if (string.IsNullOrWhiteSpace(uri))
            return;

        await ImportUriContentAsync(uri.Trim());
    }

    public async Task ImportFilePathAsync(string filePath)
    {
        ErrorMessage = null;
        string extension = Path.GetExtension(filePath).ToLowerInvariant();
        string? password = null;

        if (extension == ".npvt")
        {
            try
            {
                await SetBusyAsync(L["Working"], L["Importing"]);
                AppendLog("Ensuring npvt-decoder…");
                await _binaryManager.EnsureNpvtDecoderAsync(new Progress<string>(msg => AppendLog(msg)));
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to ensure npvt-decoder");
                await SetErrorAsync(ex.Message);
                return;
            }
            finally
            {
                await ClearBusyAsync();
            }
        }

        for (int attempt = 0; attempt < 2; attempt++)
        {
            try
            {
                await SetBusyAsync(L["Importing"], $"{L["Importing"]} {Path.GetFileName(filePath)}");
                AppendLog($"Importing {Path.GetFileName(filePath)}…");

                var imported = await _parserFactory.ImportFileAsync(filePath, password).ConfigureAwait(false);
                await UiDispatcher.RunAsync(() =>
                {
                    AddImportedProfiles(imported);
                    StatusMessage = L["ImportSuccess"];
                    ShowToast(L["ImportSuccess"]);
                });
                return;
            }
            catch (Exception ex) when (attempt == 0 && RequiresPassword(ex))
            {
                string? pwd = null;
                await UiDispatcher.RunAsync(() =>
                {
                    pwd = PasswordDialog.Prompt(
                        Application.Current.MainWindow,
                        L["PasswordTitle"],
                        L["PasswordRequired"]);
                });

                if (string.IsNullOrEmpty(pwd))
                {
                    AppendLog("Import cancelled.");
                    await UiDispatcher.RunAsync(() => StatusMessage = L["Ready"]);
                    return;
                }
                password = pwd;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Import failed for {File}", filePath);
                await SetErrorAsync(ex.Message);
                return;
            }
            finally
            {
                await ClearBusyAsync();
            }
        }
    }

    [RelayCommand(CanExecute = nameof(CanConnect))]
    private async Task ConnectAsync()
    {
        if (SelectedProfile is null) return;

        if (SelectedMode == ConnectionMode.Tun && !ElevationHelper.IsRunningAsAdmin())
        {
            bool restart = false;
            await UiDispatcher.RunAsync(() =>
            {
                restart = MessageBox.Show(
                    L["ElevationRequired"],
                    L["ElevationTitle"],
                    MessageBoxButton.YesNo,
                    MessageBoxImage.Warning) == MessageBoxResult.Yes;
            });

            if (restart && ElevationHelper.TryRestartAsAdmin())
                Application.Current.Shutdown();
            return;
        }

        try
        {
            ErrorMessage = null;
            await SetBusyAsync(L["Connecting"], L["Connecting"]);
            AppendLog("Ensuring binaries…");
            await _binaryManager.EnsureAllAsync(new Progress<string>(msg => AppendLog(msg)));

            AppendLog($"Connecting to {SelectedProfile.Name}…");
            await _connectionService.ConnectAsync(SelectedProfile, SelectedMode).ConfigureAwait(false);

            await UiDispatcher.RunAsync(() =>
            {
                StatusMessage = L["Connected"];
                ShowToast(L["Connected"]);
            });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Connect failed");
            await SetErrorAsync(ex.Message);
        }
        finally
        {
            await ClearBusyAsync();
            await UiDispatcher.RunAsync(() =>
            {
                ConnectCommand.NotifyCanExecuteChanged();
                DisconnectCommand.NotifyCanExecuteChanged();
            });
        }
    }

    private bool CanConnect =>
        !IsBusy &&
        SelectedProfile is not null &&
        ConnectionState is ConnectionState.Disconnected or ConnectionState.Error;

    [RelayCommand(CanExecute = nameof(CanDisconnect))]
    private async Task DisconnectAsync()
    {
        try
        {
            await SetBusyAsync(L["Disconnecting"], L["Disconnecting"]);
            await _connectionService.DisconnectAsync().ConfigureAwait(false);
            await UiDispatcher.RunAsync(() => StatusMessage = L["Disconnected"]);
            AppendLog("Disconnected.");
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Disconnect failed");
            await SetErrorAsync(ex.Message);
        }
        finally
        {
            await ClearBusyAsync();
            await UiDispatcher.RunAsync(() =>
            {
                ConnectCommand.NotifyCanExecuteChanged();
                DisconnectCommand.NotifyCanExecuteChanged();
            });
        }
    }

    private bool CanDisconnect =>
        !IsBusy &&
        ConnectionState is ConnectionState.Connected or ConnectionState.Connecting;

    [RelayCommand]
    private void RemoveProfile()
    {
        if (SelectedProfile is null) return;

        var profile = SelectedProfile;
        if (MessageBox.Show(
                L["RemoveConfirm"],
                L["RemoveTitle"],
                MessageBoxButton.YesNo,
                MessageBoxImage.Question) != MessageBoxResult.Yes)
            return;

        _profileService.Remove(profile.Id);
        Profiles.Remove(profile);
        SelectedProfile = Profiles.FirstOrDefault();
        OnPropertyChanged(nameof(IsEmpty));
        AppendLog($"Removed: {profile.Name}");
    }

    [RelayCommand]
    private void ClearLog()
    {
        LogLines.Clear();
        ErrorMessage = null;
    }

    public async Task DisconnectOnExitAsync()
    {
        if (ConnectionState is ConnectionState.Connected or ConnectionState.Connecting)
        {
            try
            {
                await _connectionService.DisconnectAsync().ConfigureAwait(false);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Disconnect on exit failed");
            }
        }
    }

    partial void OnSelectedProfileChanged(ServerProfile? value)
    {
        SelectedProfileDetails = value is null ? null : ProfileDisplayInfo.From(value);
        ConnectCommand.NotifyCanExecuteChanged();
    }

    partial void OnConnectionStateChanged(ConnectionState value)
    {
        ConnectCommand.NotifyCanExecuteChanged();
        DisconnectCommand.NotifyCanExecuteChanged();
    }

    partial void OnIsBusyChanged(bool value)
    {
        ConnectCommand.NotifyCanExecuteChanged();
        DisconnectCommand.NotifyCanExecuteChanged();
    }

    private async Task ImportUriContentAsync(string content)
    {
        try
        {
            ErrorMessage = null;
            await SetBusyAsync(L["Importing"], L["Importing"]);
            var imported = await _parserFactory.ParseAsync(content).ConfigureAwait(false);
            await UiDispatcher.RunAsync(() =>
            {
                AddImportedProfiles(imported);
                StatusMessage = L["ImportSuccess"];
                ShowToast(L["ImportSuccess"]);
            });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "URI import failed");
            await SetErrorAsync(ex.Message);
        }
        finally
        {
            await ClearBusyAsync();
        }
    }

    private void AddImportedProfiles(IReadOnlyList<ServerProfile> imported)
    {
        foreach (var profile in imported)
        {
            _profileService.Add(profile);
            Profiles.Add(profile);
        }

        OnPropertyChanged(nameof(IsEmpty));

        if (imported.Count > 0)
        {
            SelectedProfile = imported[0];
            AppendLog($"Imported: {imported[0].Name}");
        }
    }

    private static bool RequiresPassword(Exception ex) =>
        ex.Message.Contains("password", StringComparison.OrdinalIgnoreCase);

    private void OnConnectionStateChanged(object? sender, ConnectionState state) =>
        UiDispatcher.Run(() =>
        {
            ConnectionState = state;
            StatusMessage = state switch
            {
                ConnectionState.Connected => L["Connected"],
                ConnectionState.Disconnected => L["Disconnected"],
                ConnectionState.Connecting => L["Connecting"],
                ConnectionState.Disconnecting => L["Disconnecting"],
                ConnectionState.Error => L["ConnectionFailed"],
                _ => state.ToString()
            };
        });

    private void OnLogReceived(object? sender, string line) =>
        UiDispatcher.Run(() => AppendLog(line));

    private void AppendLog(string line)
    {
        string redacted = LogRedactor.Redact(line);
        LogLines.Add($"[{DateTime.Now:HH:mm:ss}] {redacted}");
        while (LogLines.Count > MaxLogLines)
            LogLines.RemoveAt(0);
    }

    private async Task SetBusyAsync(string busyMessage, string status)
    {
        await UiDispatcher.RunAsync(() =>
        {
            IsBusy = true;
            BusyMessage = busyMessage;
            StatusMessage = status;
        });
    }

    private async Task ClearBusyAsync()
    {
        await UiDispatcher.RunAsync(() =>
        {
            IsBusy = false;
            BusyMessage = string.Empty;
        });
    }

    private async Task SetErrorAsync(string message)
    {
        await UiDispatcher.RunAsync(() =>
        {
            ErrorMessage = message;
            StatusMessage = L["ImportFailed"];
            AppendLog(message);
        });
    }

    private void ShowToast(string message)
    {
        ToastMessage = message;
        _ = ClearToastAfterDelayAsync();
    }

    private async Task ClearToastAfterDelayAsync()
    {
        await Task.Delay(3500);
        await UiDispatcher.RunAsync(() => ToastMessage = null);
    }

    private void RefreshLocalizedStatus()
    {
        StatusMessage = ConnectionState switch
        {
            ConnectionState.Connected => L["Connected"],
            ConnectionState.Disconnected => L["Disconnected"],
            ConnectionState.Connecting => L["Connecting"],
            ConnectionState.Disconnecting => L["Disconnecting"],
            ConnectionState.Error => L["ConnectionFailed"],
            _ => L["Ready"]
        };
        OnPropertyChanged(nameof(L));
    }

    private bool EnsureDisclaimerAccepted()
    {
        if (File.Exists(Constants.DisclaimerFlagFile))
            return true;

        var result = MessageBox.Show(
            L["DisclaimerText"],
            L["DisclaimerTitle"],
            MessageBoxButton.YesNo,
            MessageBoxImage.Information);

        if (result != MessageBoxResult.Yes)
            return false;

        try
        {
            Constants.EnsureDirectories();
            File.WriteAllText(Constants.DisclaimerFlagFile, DateTimeOffset.UtcNow.ToString("O"));
        }
        catch { }

        return true;
    }

    public void Dispose()
    {
        _connectionService.StateChanged -= OnConnectionStateChanged;
        _connectionService.LogReceived -= OnLogReceived;
        L.PropertyChanged -= (_, _) => RefreshLocalizedStatus();
    }
}

