using System.Windows;
using System.Windows.Threading;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Core;
using NapsternetVClient.Parsers;
using NapsternetVClient.Services;
using NapsternetVClient.ViewModels;
using NapsternetVClient.Views;

namespace NapsternetVClient;

public partial class App : Application
{
    private ILoggerFactory? _loggerFactory;
    private ConnectionService? _connectionService;
    private MainViewModel? _mainViewModel;
    private MainWindow? _mainWindow;

    protected override async void OnStartup(StartupEventArgs e)
    {
        base.OnStartup(e);

        DispatcherUnhandledException += OnDispatcherUnhandledException;
        AppDomain.CurrentDomain.UnhandledException += OnDomainUnhandledException;
        TaskScheduler.UnobservedTaskException += OnUnobservedTaskException;

        _loggerFactory = LoggerFactory.Create(builder =>
        {
            builder.AddDebug();
            builder.SetMinimumLevel(LogLevel.Information);
        });

        var logger = _loggerFactory.CreateLogger<App>();
        logger.LogInformation("NapsternetV Client starting");

        var connectionService = new ConnectionService(_loggerFactory.CreateLogger<ConnectionService>());
        _connectionService = connectionService;
        connectionService.RecoverDirtySession();

        var profileService = new ProfileService(_loggerFactory.CreateLogger<ProfileService>());
        var binaryManager = new BinaryManager(_loggerFactory.CreateLogger<BinaryManager>());
        var parserFactory = new ParserFactory(_loggerFactory);

        _mainViewModel = new MainViewModel(
            profileService,
            connectionService,
            binaryManager,
            parserFactory,
            _loggerFactory.CreateLogger<MainViewModel>());

        _mainWindow = new MainWindow(_mainViewModel);
        MainWindow = _mainWindow;

        await _mainViewModel.InitializeAsync();
        if (Current.MainWindow is null)
            return;

        _mainWindow.Show();
        SessionEnding += OnSessionEnding;
    }

    private void OnDispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
    {
        _loggerFactory?.CreateLogger<App>().LogError(e.Exception, "Unhandled UI exception");
        MessageBox.Show(
            $"An error occurred:\n\n{e.Exception.Message}",
            "Error",
            MessageBoxButton.OK,
            MessageBoxImage.Error);
        e.Handled = true;
    }

    private void OnDomainUnhandledException(object sender, UnhandledExceptionEventArgs e)
    {
        if (e.ExceptionObject is Exception ex)
            _loggerFactory?.CreateLogger<App>().LogError(ex, "Unhandled domain exception");
    }

    private void OnUnobservedTaskException(object? sender, UnobservedTaskExceptionEventArgs e)
    {
        _loggerFactory?.CreateLogger<App>().LogError(e.Exception, "Unobserved task exception");
        e.SetObserved();
    }

    private async void OnSessionEnding(object sender, SessionEndingCancelEventArgs e) =>
        await CleanupAsync();

    protected override async void OnExit(ExitEventArgs e)
    {
        await CleanupAsync();
        _loggerFactory?.Dispose();
        base.OnExit(e);
    }

    private async Task CleanupAsync()
    {
        if (_mainWindow is not null)
            _mainWindow.PrepareForExit();

        if (_mainViewModel is not null)
            await _mainViewModel.DisconnectOnExitAsync();

        _mainViewModel?.Dispose();
        _connectionService?.Dispose();
    }
}

using System.Globalization;
using System.Windows.Data;
using NapsternetVClient.Models;

namespace NapsternetVClient.ViewModels;

public sealed class ModeEqualsConverter : IValueConverter
{
    public static ModeEqualsConverter Instance { get; } = new();

    public object Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is ConnectionMode mode && parameter is string s &&
            Enum.TryParse<ConnectionMode>(s, out var target))
            return mode == target;
        return false;
    }

    public object ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is true && parameter is string s &&
            Enum.TryParse<ConnectionMode>(s, out var mode))
            return mode;
        return Binding.DoNothing;
    }
}

using System.Collections.Specialized;
using System.ComponentModel;
using System.IO;
using System.Windows;
using NapsternetVClient.ViewModels;

namespace NapsternetVClient.Views;

public partial class MainWindow : Window
{
    private static readonly string[] AllowedExtensions = [".npvt", ".npv4", ".npv", ".npv2"];

    private readonly MainViewModel _viewModel;
    private bool _isExiting;

    public MainWindow(MainViewModel viewModel)
    {
        InitializeComponent();
        _viewModel = viewModel;
        DataContext = viewModel;

        viewModel.LogLines.CollectionChanged += LogLines_CollectionChanged;
        Closed += (_, _) => viewModel.LogLines.CollectionChanged -= LogLines_CollectionChanged;
    }

    private void LogLines_CollectionChanged(object? sender, NotifyCollectionChangedEventArgs e)
    {
        if (e.Action == NotifyCollectionChangedAction.Add && LogListBox.Items.Count > 0)
            LogListBox.ScrollIntoView(LogListBox.Items[^1]);
    }

    private void Window_StateChanged(object sender, EventArgs e)
    {
        if (WindowState == WindowState.Minimized)
            HideToTray();
    }

    private void Window_Closing(object? sender, CancelEventArgs e)
    {
        if (_isExiting)
            return;

        e.Cancel = true;

        if (_viewModel.ConnectionState is Models.ConnectionState.Connected or Models.ConnectionState.Connecting)
        {
            var result = MessageBox.Show(
                _viewModel.L["ExitConfirm"],
                _viewModel.L["ExitTitle"],
                MessageBoxButton.YesNo,
                MessageBoxImage.Question);

            if (result != MessageBoxResult.Yes)
                return;

            _isExiting = true;
            Application.Current.Shutdown();
            return;
        }

        _isExiting = true;
        Application.Current.Shutdown();
    }

    private void Window_DragOver(object sender, DragEventArgs e)
    {
        if (e.Data.GetDataPresent(DataFormats.FileDrop))
        {
            e.Effects = DragDropEffects.Copy;
            e.Handled = true;
        }
    }

    private async void Window_Drop(object sender, DragEventArgs e)
    {
        if (!e.Data.GetDataPresent(DataFormats.FileDrop))
            return;

        if (e.Data.GetData(DataFormats.FileDrop) is not string[] files || files.Length == 0)
            return;

        string file = files[0];
        string ext = Path.GetExtension(file).ToLowerInvariant();
        if (!AllowedExtensions.Contains(ext))
            return;

        await _viewModel.ImportFilePathAsync(file);
    }

    private void HideToTray()
    {
        Hide();
        TrayIcon.Visibility = Visibility.Visible;
        ShowInTaskbar = false;
    }

    private void ShowFromTray()
    {
        TrayIcon.Visibility = Visibility.Collapsed;
        ShowInTaskbar = true;
        Show();
        WindowState = WindowState.Normal;
        Activate();
    }

    private void TrayIcon_TrayMouseDoubleClick(object sender, RoutedEventArgs e) => ShowFromTray();
    private void TrayShow_Click(object sender, RoutedEventArgs e) => ShowFromTray();

    private void TrayExit_Click(object sender, RoutedEventArgs e)
    {
        _isExiting = true;
        Application.Current.Shutdown();
    }

    public void PrepareForExit() => _isExiting = true;
}

