using System.Text.Json;
using System.Text.Json.Serialization;
using NapsternetVClient.Models;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Parsers;

public static class NpvtPayloadParser
{
    public static string ExtractJsonPayload(string raw)
    {
        raw = raw.Trim();
        if (raw.StartsWith('{') || raw.StartsWith('['))
            return raw;

        int arrayStart = raw.IndexOf('[');
        int objectStart = raw.IndexOf('{');
        int start = arrayStart >= 0 && objectStart >= 0
            ? Math.Min(arrayStart, objectStart)
            : Math.Max(arrayStart, objectStart);

        if (start < 0)
            throw new FormatException("Decoder output does not contain JSON.");

        return raw[start..].Trim();
    }

    public static IReadOnlyList<ServerProfile> ParseProfiles(string json, string sourceName)
    {
        json = ExtractJsonPayload(json);

        if (json.StartsWith('['))
            return ParseNapsternetArray(json, sourceName);

        NpvWrapper? wrapper = JsonHelper.Deserialize<NpvWrapper>(json);
        if (wrapper?.Config is not null)
            return [NpvtProfileMapper.MapFromWrapper(wrapper, sourceName)];

        NpvConfig? directConfig = JsonHelper.Deserialize<NpvConfig>(json);
        if (directConfig is not null && !string.IsNullOrEmpty(directConfig.Address))
            return [NpvtProfileMapper.MapConfig(directConfig, "vmess", sourceName)];

        throw new FormatException("Decoded NPVT content is not a recognized config structure.");
    }

    private static IReadOnlyList<ServerProfile> ParseNapsternetArray(string json, string sourceName)
    {
        var entries = JsonHelper.Deserialize<List<NapsternetProfileEntry>>(json)
            ?? throw new FormatException("Failed to parse Napsternet profile array.");

        if (entries.Count == 0)
            throw new FormatException("NPVT file contains no profiles.");

        var profiles = new List<ServerProfile>(entries.Count);
        foreach (var entry in entries)
        {
            if (entry.V2rayProfile is null)
                continue;

            string name = entry.Name
                ?? entry.V2rayProfile.Remarks
                ?? sourceName;

            if (!string.IsNullOrWhiteSpace(entry.V2rayProfile.V2rayJson))
            {
                profiles.Add(MapFromV2rayJson(entry.V2rayProfile.V2rayJson, name));
                continue;
            }

            if (!string.IsNullOrWhiteSpace(entry.V2rayProfile.Server))
            {
                profiles.Add(new ServerProfile
                {
                    Name = name,
                    Protocol = ProxyProtocol.Vmess,
                    Address = entry.V2rayProfile.Server,
                    Port = int.TryParse(entry.V2rayProfile.ServerPort, out int port) ? port : 443
                });
            }
        }

        if (profiles.Count == 0)
            throw new FormatException("NPVT profile array had no usable V2RAY entries.");

        return profiles;
    }

    private static ServerProfile MapFromV2rayJson(string v2rayJson, string name)
    {
        using var doc = JsonDocument.Parse(v2rayJson);
        var root = doc.RootElement;

        if (!TryGetProxyOutbound(root, out var outbound))
            throw new FormatException("v2rayJson does not contain a proxy outbound.");

        string protocol = outbound.GetProperty("protocol").GetString()?.ToLowerInvariant()
            ?? throw new FormatException("Proxy outbound is missing protocol.");

        var profile = new ServerProfile
        {
            Name = root.TryGetProperty("remarks", out var remarks) && remarks.ValueKind == JsonValueKind.String
                ? remarks.GetString() ?? name
                : name
        };

        MapOutboundSettings(outbound, protocol, profile);
        MapStreamSettings(outbound, profile);
        MapDns(root, profile);
        return profile;
    }

    private static bool TryGetProxyOutbound(JsonElement root, out JsonElement outbound)
    {
        outbound = default;
        if (!root.TryGetProperty("outbounds", out var outbounds) || outbounds.ValueKind != JsonValueKind.Array)
            return false;

        JsonElement? fallback = null;
        foreach (var candidate in outbounds.EnumerateArray())
        {
            if (candidate.ValueKind != JsonValueKind.Object)
                continue;

            string protocol = candidate.TryGetProperty("protocol", out var proto)
                ? proto.GetString()?.ToLowerInvariant() ?? string.Empty
                : string.Empty;

            if (protocol is "freedom" or "blackhole" or "dns")
                continue;

            string? tag = candidate.TryGetProperty("tag", out var tagEl) ? tagEl.GetString() : null;
            if (string.Equals(tag, "proxy", StringComparison.OrdinalIgnoreCase))
            {
                outbound = candidate;
                return true;
            }

            fallback ??= candidate;
        }

        if (fallback is null)
            return false;

        outbound = fallback.Value;
        return true;
    }

    private static void MapOutboundSettings(JsonElement outbound, string protocol, ServerProfile profile)
    {
        profile.Protocol = protocol switch
        {
            "vmess" => ProxyProtocol.Vmess,
            "vless" => ProxyProtocol.Vless,
            "trojan" => ProxyProtocol.Trojan,
            "shadowsocks" or "ss" => ProxyProtocol.Shadowsocks,
            "socks" => ProxyProtocol.Socks,
            _ => throw new NotSupportedException($"Unsupported protocol in NPVT config: {protocol}")
        };

        if (!outbound.TryGetProperty("settings", out var settings))
            return;

        switch (profile.Protocol)
        {
            case ProxyProtocol.Vmess:
            case ProxyProtocol.Vless:
                if (settings.TryGetProperty("vnext", out var vnext) &&
                    vnext.ValueKind == JsonValueKind.Array &&
                    vnext.GetArrayLength() > 0)
                {
                    var server = vnext[0];
                    profile.Address = server.GetProperty("address").GetString() ?? string.Empty;
                    profile.Port = server.GetProperty("port").GetInt32();
                    if (server.TryGetProperty("users", out var users) &&
                        users.ValueKind == JsonValueKind.Array &&
                        users.GetArrayLength() > 0)
                    {
                        var user = users[0];
                        profile.UserId = user.TryGetProperty("id", out var id) ? id.GetString() ?? string.Empty : string.Empty;
                        profile.AlterId = user.TryGetProperty("alterId", out var alterId) ? alterId.GetInt32() : 0;
                        profile.Security = user.TryGetProperty("security", out var sec) ? sec.GetString() ?? "auto" : "auto";
                        profile.Flow = user.TryGetProperty("flow", out var flow) ? flow.GetString() ?? string.Empty : string.Empty;
                    }
                }
                break;

            case ProxyProtocol.Trojan:
            case ProxyProtocol.Shadowsocks:
            case ProxyProtocol.Socks:
                if (settings.TryGetProperty("servers", out var servers) &&
                    servers.ValueKind == JsonValueKind.Array &&
                    servers.GetArrayLength() > 0)
                {
                    var server = servers[0];
                    profile.Address = server.GetProperty("address").GetString() ?? string.Empty;
                    profile.Port = server.GetProperty("port").GetInt32();
                    if (server.TryGetProperty("password", out var password))
                        profile.Password = password.GetString() ?? string.Empty;
                    if (server.TryGetProperty("method", out var method))
                        profile.Security = method.GetString() ?? profile.Security;
                    if (server.TryGetProperty("users", out var users) &&
                        users.ValueKind == JsonValueKind.Array &&
                        users.GetArrayLength() > 0)
                    {
                        var user = users[0];
                        profile.UserId = user.TryGetProperty("user", out var u) ? u.GetString() ?? string.Empty : string.Empty;
                        if (user.TryGetProperty("pass", out var pass))
                            profile.Password = pass.GetString() ?? profile.Password;
                    }
                }
                break;
        }
    }

    private static void MapStreamSettings(JsonElement outbound, ServerProfile profile)
    {
        if (!outbound.TryGetProperty("streamSettings", out var stream))
            return;

        if (stream.TryGetProperty("network", out var network))
            profile.Network = NpvtProfileMapper.ParseTransport(network.GetString() ?? "tcp");

        if (stream.TryGetProperty("security", out var security))
            profile.TlsSecurity = security.GetString() ?? string.Empty;

        if (stream.TryGetProperty("wsSettings", out var ws))
        {
            profile.WsPath = ws.TryGetProperty("path", out var path) ? path.GetString() ?? string.Empty : string.Empty;
            if (ws.TryGetProperty("host", out var host))
                profile.WsHost = host.GetString() ?? string.Empty;
            else if (ws.TryGetProperty("headers", out var headers) &&
                     headers.TryGetProperty("Host", out var hostHeader))
                profile.WsHost = hostHeader.GetString() ?? string.Empty;
        }

        if (stream.TryGetProperty("grpcSettings", out var grpc))
        {
            profile.GrpcServiceName = grpc.TryGetProperty("serviceName", out var serviceName)
                ? serviceName.GetString() ?? string.Empty
                : string.Empty;
            profile.GrpcMode = grpc.TryGetProperty("multiMode", out var multiMode) && multiMode.GetBoolean()
                ? "multi"
                : "gun";
        }

        if (stream.TryGetProperty("tlsSettings", out var tls))
            ApplyTlsSettings(tls, profile);
        else if (stream.TryGetProperty("realitySettings", out var reality))
            ApplyRealitySettings(reality, profile);
    }

    private static void ApplyTlsSettings(JsonElement tls, ServerProfile profile)
    {
        profile.Sni = tls.TryGetProperty("serverName", out var sni) ? sni.GetString() ?? string.Empty : string.Empty;
        profile.AllowInsecure = tls.TryGetProperty("allowInsecure", out var allowInsecure) && allowInsecure.GetBoolean();
        profile.Fingerprint = tls.TryGetProperty("fingerprint", out var fp) ? fp.GetString() ?? string.Empty : string.Empty;

        if (tls.TryGetProperty("alpn", out var alpn) && alpn.ValueKind == JsonValueKind.Array)
        {
            profile.Alpn = string.Join(",",
                alpn.EnumerateArray()
                    .Where(item => item.ValueKind == JsonValueKind.String)
                    .Select(item => item.GetString())
                    .Where(item => !string.IsNullOrWhiteSpace(item)));
        }
    }

    private static void ApplyRealitySettings(JsonElement reality, ServerProfile profile)
    {
        profile.TlsSecurity = "reality";
        profile.Sni = reality.TryGetProperty("serverName", out var sni) ? sni.GetString() ?? string.Empty : string.Empty;
        profile.RealityPublicKey = reality.TryGetProperty("publicKey", out var pk) ? pk.GetString() ?? string.Empty : string.Empty;
        profile.RealityShortId = reality.TryGetProperty("shortId", out var sid) ? sid.GetString() ?? string.Empty : string.Empty;
        profile.RealitySpiderX = reality.TryGetProperty("spiderX", out var spider) ? spider.GetString() ?? string.Empty : string.Empty;
        profile.Fingerprint = reality.TryGetProperty("fingerprint", out var fp) ? fp.GetString() ?? string.Empty : string.Empty;
    }

    private static void MapDns(JsonElement root, ServerProfile profile)
    {
        if (!root.TryGetProperty("dns", out var dns) ||
            !dns.TryGetProperty("servers", out var servers) ||
            servers.ValueKind != JsonValueKind.Array)
        {
            return;
        }

        foreach (var server in servers.EnumerateArray())
        {
            if (server.ValueKind == JsonValueKind.String)
            {
                profile.DnsServer = server.GetString();
                return;
            }

            if (server.ValueKind == JsonValueKind.Object &&
                server.TryGetProperty("address", out var address) &&
                address.ValueKind == JsonValueKind.String)
            {
                profile.DnsServer = address.GetString();
                return;
            }
        }
    }

