public static string ExtractJsonPayload(string raw)
{
    raw = raw.Trim();
    if (raw.StartsWith('{') || raw.StartsWith('['))
        return ExtractBalancedJson(raw, 0);

    int arrayStart = raw.IndexOf('[');
    int objectStart = raw.IndexOf('{');
    int start = arrayStart >= 0 && objectStart >= 0
        ? Math.Min(arrayStart, objectStart)
        : Math.Max(arrayStart, objectStart);

    if (start < 0)
        throw new FormatException("Decoder output does not contain JSON.");

    return ExtractBalancedJson(raw, start);
}

private static string ExtractBalancedJson(string raw, int start)
{
    char open = raw[start];
    char close = open switch
    {
        '[' => ']',
        '{' => '}',
        _ => throw new FormatException("Decoder output does not start with JSON.")
    };

    int depth = 0;
    bool inString = false;
    bool escape = false;

    for (int i = start; i < raw.Length; i++)
    {
        char c = raw[i];
        if (inString)
        {
            if (escape)
                escape = false;
            else if (c == '\\')
                escape = true;
            else if (c == '"')
                inString = false;

            continue;
        }

        if (c == '"')
        {
            inString = true;
            continue;
        }

        if (c == open)
            depth++;
        else if (c == close)
        {
            depth--;
            if (depth == 0)
                return raw[start..(i + 1)];
        }
    }

    throw new FormatException("Decoder output contains incomplete JSON.");
}

