using System.Diagnostics;
using System.Net;
using System.Net.Sockets;
using System.Text;

namespace NapsternetVClient.Network;

public static class Socks5LatencyProbe
{
    private const string TestHost = "www.gstatic.com";
    private const int TestPort = 443;
    private const string TestPath = "/generate_204";

    public static async Task<int?> MeasureRealDelayAsync(
        int socksPort,
        string host = "127.0.0.1",
        int timeoutMs = 15000,
        CancellationToken cancellationToken = default)
    {
        using var timeoutCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
        timeoutCts.CancelAfter(timeoutMs);

        try
        {
            var sw = Stopwatch.StartNew();
            using var tcp = new TcpClient();
            await tcp.ConnectAsync(host, socksPort, timeoutCts.Token).ConfigureAwait(false);

            await using NetworkStream stream = tcp.GetStream();
            await PerformSocks5ConnectAsync(stream, TestHost, TestPort, timeoutCts.Token).ConfigureAwait(false);

            string request =
                $"HEAD {TestPath} HTTP/1.1\r\n" +
                $"Host: {TestHost}\r\n" +
                "Connection: close\r\n\r\n";

            byte[] requestBytes = Encoding.ASCII.GetBytes(request);
            await stream.WriteAsync(requestBytes, timeoutCts.Token).ConfigureAwait(false);

            byte[] buffer = new byte[64];
            int read = await stream.ReadAsync(buffer, timeoutCts.Token).ConfigureAwait(false);
            if (read <= 0)
                return null;

            string response = Encoding.ASCII.GetString(buffer, 0, read);
            if (!response.StartsWith("HTTP/1.1 204", StringComparison.Ordinal) &&
                !response.StartsWith("HTTP/1.0 204", StringComparison.Ordinal) &&
                !response.StartsWith("HTTP/1.1 200", StringComparison.Ordinal))
            {
                return null;
            }

            return (int)Math.Max(1, sw.ElapsedMilliseconds);
        }
        catch (OperationCanceledException)
        {
            return null;
        }
        catch
        {
            return null;
        }
    }

    private static async Task PerformSocks5ConnectAsync(
        NetworkStream stream,
        string targetHost,
        int targetPort,
        CancellationToken cancellationToken)
    {
        await stream.WriteAsync(new byte[] { 0x05, 0x01, 0x00 }, cancellationToken).ConfigureAwait(false);

        byte[] methodResponse = new byte[2];
        await ReadExactAsync(stream, methodResponse, cancellationToken).ConfigureAwait(false);
        if (methodResponse[0] != 0x05 || methodResponse[1] != 0x00)
            throw new InvalidOperationException("SOCKS5 handshake failed.");

        byte[] hostBytes = Encoding.ASCII.GetBytes(targetHost);
        var request = new byte[7 + hostBytes.Length];
        request[0] = 0x05;
        request[1] = 0x01;
        request[2] = 0x00;
        request[3] = 0x03;
        request[4] = (byte)hostBytes.Length;
        hostBytes.CopyTo(request, 5);
        request[5 + hostBytes.Length] = (byte)(targetPort >> 8);
        request[6 + hostBytes.Length] = (byte)(targetPort & 0xFF);

        await stream.WriteAsync(request, cancellationToken).ConfigureAwait(false);

        byte[] header = new byte[4];
        await ReadExactAsync(stream, header, cancellationToken).ConfigureAwait(false);
        if (header[1] != 0x00)
            throw new InvalidOperationException($"SOCKS5 connect failed (code {header[1]}).");

        int remaining = header[3] switch
        {
            0x01 => 4 + 2,
            0x03 => header[4] + 2,
            0x04 => 16 + 2,
            _ => throw new InvalidOperationException("Unsupported SOCKS5 address type.")
        };

        byte[] rest = new byte[remaining];
        await ReadExactAsync(stream, rest, cancellationToken).ConfigureAwait(false);
    }

    private static async Task ReadExactAsync(NetworkStream stream, byte[] buffer, CancellationToken cancellationToken)
    {
        int offset = 0;
        while (offset < buffer.Length)
        {
            int read = await stream.ReadAsync(buffer.AsMemory(offset, buffer.Length - offset), cancellationToken)
                .ConfigureAwait(false);
            if (read == 0)
                throw new EndOfStreamException("Unexpected end of SOCKS5 stream.");
            offset += read;
        }
    }
}

using Microsoft.Extensions.Logging;
using NapsternetVClient.Converters;
using NapsternetVClient.Core;
using NapsternetVClient.Models;
using NapsternetVClient.Network;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Services;

public sealed class LatencyTestService : IDisposable
{
    private readonly BinaryManager _binaryManager;
    private readonly XrayProcessManager _xrayManager;
    private readonly ILogger? _logger;
    private bool _disposed;

    public LatencyTestService(ILogger? logger = null)
    {
        _logger = logger;
        _binaryManager = new BinaryManager(logger);
        _xrayManager = new XrayProcessManager(logger);
    }

    public async Task<int?> TestProfileAsync(
        ServerProfile profile,
        IProgress<string>? progress = null,
        CancellationToken cancellationToken = default)
    {
        ObjectDisposedException.ThrowIf(_disposed, this);

        int socksPort = FindFreePort();
        string configPath = Path.Combine(Constants.ConfigDir, $"latency_{profile.Id}.json");

        progress?.Report($"Preparing xray for {profile.Name}…");
        await _binaryManager.EnsureForConnectAsync(ConnectionMode.SystemProxy, progress, cancellationToken)
            .ConfigureAwait(false);

        string config = XrayConfigBuilder.Build(profile, socksPort, Constants.DefaultHttpPort);
        await File.WriteAllTextAsync(configPath, config, cancellationToken).ConfigureAwait(false);

        try
        {
            progress?.Report($"Testing {profile.Name}…");
            await _xrayManager.StartAsync(configPath, socksPort, cancellationToken).ConfigureAwait(false);

            int? delay = await Socks5LatencyProbe.MeasureRealDelayAsync(socksPort, cancellationToken: cancellationToken)
                .ConfigureAwait(false);

            _logger?.LogInformation("Latency for {Profile}: {Delay} ms", profile.Name, delay?.ToString() ?? "timeout");
            return delay;
        }
        finally
        {
            await _xrayManager.StopAsync().ConfigureAwait(false);
            try { File.Delete(configPath); } catch { }
        }
    }

    private static int FindFreePort()
    {
        using var listener = new System.Net.Sockets.TcpListener(System.Net.IPAddress.Loopback, 0);
        listener.Start();
        int port = ((System.Net.IPEndPoint)listener.LocalEndpoint).Port;
        listener.Stop();
        return port;
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _xrayManager.Dispose();
    }
}

