private async Task WaitForReadyAsync(int socksPort, CancellationToken cancellationToken)
{
    for (var attempt = 0; attempt < 60; attempt++)
    {
        cancellationToken.ThrowIfCancellationRequested();

        if (_process is null || _process.HasExited)
            throw new InvalidOperationException("xray.exe exited during startup. Check the log for details.");

        if (await IsPortOpenAsync("127.0.0.1", socksPort, cancellationToken).ConfigureAwait(false))
            return;

        await Task.Delay(150, cancellationToken).ConfigureAwait(false);
    }

    throw new TimeoutException("xray-core did not become ready in time.");
}

private static async Task<bool> IsPortOpenAsync(string host, int port, CancellationToken cancellationToken)
{
    try
    {
        using var client = new TcpClient();
        using var timeout = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
        timeout.CancelAfter(300);
        await client.ConnectAsync(host, port, timeout.Token).ConfigureAwait(false);
        return true;
    }
    catch
    {
        return false;
    }
}

