public static async Task ValidateConfigAsync(string configPath, CancellationToken cancellationToken = default)
{
    var psi = new ProcessStartInfo
    {
        FileName = Constants.XrayExePath,
        Arguments = $"run -test -c \"{configPath}\"",
        WorkingDirectory = Constants.BinDir,
        UseShellExecute = false,
        RedirectStandardOutput = true,
        RedirectStandardError = true,
        CreateNoWindow = true,
        StandardOutputEncoding = Encoding.UTF8,
        StandardErrorEncoding = Encoding.UTF8
    };

    using var process = Process.Start(psi)
        ?? throw new InvalidOperationException("Failed to start xray.exe for config validation.");

    string stdout = await process.StandardOutput.ReadToEndAsync(cancellationToken).ConfigureAwait(false);
    string stderr = await process.StandardError.ReadToEndAsync(cancellationToken).ConfigureAwait(false);
    await process.WaitForExitAsync(cancellationToken).ConfigureAwait(false);

    if (process.ExitCode == 0)
        return;

    string details = ExtractXrayError(stdout, stderr);
    throw new InvalidOperationException(
        string.IsNullOrWhiteSpace(details)
            ? $"Invalid xray config (exit {process.ExitCode})."
            : details);
}

private string BuildStartupError(string headline)
{
    string details = string.Join(Environment.NewLine, _recentLogs.Where(l => !string.IsNullOrWhiteSpace(l)));
    return string.IsNullOrWhiteSpace(details) ? headline : $"{headline}{Environment.NewLine}{details}";
}

private static string ExtractXrayError(string stdout, string stderr)
{
    foreach (string line in (stderr + Environment.NewLine + stdout).Split('\n'))
    {
        string trimmed = line.Trim();
        if (trimmed.Contains("Failed to start", StringComparison.OrdinalIgnoreCase) ||
            trimmed.Contains("failed to", StringComparison.OrdinalIgnoreCase) ||
            trimmed.Contains("removed", StringComparison.OrdinalIgnoreCase))
        {
            return trimmed;
        }
    }

    return stderr.Trim();
